                  <Play className="w-4 h-4" aria-hidden="true" />
                  Watch 2-Minute Demo
                </button>
              </div>
            </motion.div>

            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.5 }}
              className="space-y-3 pt-2"
            >
              <div className="grid grid-cols-1 gap-2">
                {aiFeatureBullets.map((bullet, index) => {
                  const Icon = bullet.icon;
                  return (
                    <div key={index} className="flex items-center gap-3 text-sm text-[var(--color-text-secondary)]">
                      <div className="w-8 h-8 rounded-lg bg-[var(--color-primary)]/10 flex items-center justify-center flex-shrink-0">
                        <Icon className="w-4 h-4 text-[var(--color-primary)]" aria-hidden="true" />
                      </div>
                      <span className="font-medium">{bullet.text}</span>
                    </div>
                  );
                })}
              </div>
            </motion.div>

            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.6, delay: 0.6 }}
              className="pt-4 space-y-4"
            >
              <div className="flex flex-wrap items-center gap-x-6 gap-y-2 text-sm text-[var(--color-text-secondary)]">
                <span className="flex items-center gap-1.5">
                  <span className="font-bold text-[var(--color-text-primary)]">8+ hours</span> saved/week
                </span>
                <span className="flex items-center gap-1.5">
                  <span className="font-bold text-[var(--color-text-primary)]">3×</span> faster payments
                </span>
                <span className="flex items-center gap-1.5">
                  <span className="font-bold text-[var(--color-text-primary)]">40%</span> more profit
                </span>
              </div>

              <div className="flex items-center gap-4">
                <AppStoreBadges variant="hero" />
              </div>

              <p className="text-xs text-gray-500">
                No credit card required • 2,500+ active contractors • 
                <span className="text-[var(--color-primary)] font-medium ml-1">🎁 1 month free for next 250 downloads</span>
              </p>
            </motion.div>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.4 }}
            className="relative lg:pl-8"
          >
            <div className="absolute -inset-4 bg-gradient-to-br from-[var(--color-primary)]/10 to-transparent rounded-3xl blur-2xl"></div>
            <div className="relative">
              <DeviceFrame
                src={appMainImage}
                alt="CONSTRUKTR app — AI-powered field service management showing jobs, scheduling, and payments"
                withGlow={true}
                size="mobile"
                showBadge={true}
                className="confidence-enter"
