import { useState } from "react";
import { motion } from "framer-motion";
import { Check, Star } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from "@/components/ui/accordion";
import Toggle from "./Toggle";
import { tiers } from "@/data/pricing";
import faqsData from "../../content/faqs.json";

export default function Pricing() {
  const [isAnnual, setIsAnnual] = useState(false);

  // Calculate annual pricing (15% discount)
  const getPrice = (monthlyPrice: number) => {
    return isAnnual ? Math.round(monthlyPrice * 0.85) : monthlyPrice;
  };

  const getPeriodLabel = () => {
    return isAnnual ? "per month, billed annually" : "per month";
  };

  // Simplified feature lists (3 bullets each, benefit-led)
  const simplifiedFeatures = {
    starter: [
      "AI prices materials & labor in 30 seconds",
      "Accept payments on-site instantly", 
      "Smart scheduling prevents double-bookings"
    ],
    pro: [
      "Save 2.5 hours daily with AI routing",
      "Same-day deposits with payment processing",
      "Unlimited quotes & advanced CRM"
    ],
    enterprise: [
      "Team management with role-based access",
      "Advanced analytics & custom integrations",
      "Dedicated support with priority response"
    ]
  };

  return (
    <section id="pricing" className="py-20 section-bg-alt">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <h2 className="text-4xl lg:text-5xl font-black text-[var(--color-text-primary)] mb-6">
            Find the Perfect Plan for Your Business
          </h2>
          <p className="text-xl text-[var(--color-text-secondary)] max-w-3xl mx-auto mb-8">
            Start with a 15-day free trial. No credit card required. Scale as you grow.
          </p>

          {/* Annual Toggle */}
          <Toggle isAnnual={isAnnual} onToggle={setIsAnnual} />
        </motion.div>

        {/* Pricing Cards */}
        <div className="grid md:grid-cols-3 gap-8 mb-20">
          {tiers.map((tier, index) => (
            <motion.div
              key={tier.key}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: index * 0.1 }}
              viewport={{ once: true }}
              className="relative"
            >
              {/* Popular Badge - Fixed positioning within card */}
              {tier.isMostPopular && (
                <div className="absolute top-4 left-1/2 transform -translate-x-1/2 z-10">
                  <div className="bg-gradient-to-r from-blue-500 to-blue-600 text-white px-4 py-2 rounded-full text-sm font-bold flex items-center gap-2 shadow-lg">
                    <Star className="w-4 h-4" />
                    Most Popular
                  </div>
                </div>
              )}

              {/* Card */}
              <div className={`
                p-8 md:p-10 rounded-2xl border h-full relative
                transition-all duration-300 hover:shadow-xl
                ${
                  tier.key === 'starter' 
                    ? 'bg-white border-[rgba(15,23,42,0.08)] hover:border-green-300 shadow-[0_10px_25px_rgba(15,23,42,0.08),0_2px_8px_rgba(15,23,42,0.04)]' 
                    : tier.key === 'pro' 
                    ? 'bg-gradient-to-br from-blue-50/50 to-white border-[var(--color-primary)] border-2 shadow-[0_20px_40px_rgba(15,23,42,0.12),0_8px_16px_rgba(15,23,42,0.06)] ring-4 ring-[var(--color-primary)]/20 md:scale-105' 
                    : 'bg-white border-[rgba(15,23,42,0.08)] hover:border-purple-300 shadow-[0_10px_25px_rgba(15,23,42,0.08),0_2px_8px_rgba(15,23,42,0.04)]'
                }
              `}>

                {/* Plan Header */}
                <div className={`text-center mb-8 ${tier.isMostPopular ? 'pt-10' : 'pt-4'}`}>
                  <h3 className={`text-2xl font-bold mb-3 ${
                    tier.key === 'starter' ? 'text-green-600' :
                    tier.key === 'pro' ? 'text-[var(--color-primary)]' :
                    'text-purple-600'
                  }`}>{tier.name}</h3>

                  <div className="mb-4 pb-2">
                    <span className="text-5xl font-black text-[var(--color-text-primary)] leading-tight block py-1">
                      ${getPrice(tier.priceMonthly)}
                    </span>
                    <div className="text-[var(--color-text-secondary)] text-sm mt-2">
                      {getPeriodLabel()}
                    </div>

                    {isAnnual && (
                      <div className="text-green-600 text-sm font-medium mt-2">
                        Save ${(tier.priceMonthly - getPrice(tier.priceMonthly)) * 12}/year
                      </div>
                    )}
                  </div>
                </div>

                {/* Feature Bullets */}
                <div className="space-y-4 mb-8">
                  {simplifiedFeatures[tier.key as keyof typeof simplifiedFeatures].map((feature, i) => (
                    <div key={i} className="flex items-start gap-3">
                      <Check className="w-5 h-5 text-green-600 flex-shrink-0 mt-0.5" />
                      <span className="text-[var(--color-text-primary)] text-sm leading-relaxed">{feature}</span>
                    </div>
                  ))}
                </div>

                {/* CTA Button */}
                <Button
                  className={`w-full transition-all duration-300 font-semibold ${
                    tier.key === 'starter'
                      ? 'bg-green-600 hover:bg-green-700 text-white shadow-md hover:shadow-lg'
                      : tier.key === 'pro'
                      ? 'bg-[var(--color-primary)] hover:bg-[var(--color-primary-hover)] text-white shadow-md hover:shadow-lg'
                      : 'bg-purple-600 hover:bg-purple-700 text-white shadow-md hover:shadow-lg'
                  }`}
                  style={{ borderRadius: '8px', height: '48px' }}
                >
                  {tier.cta}
                </Button>

                {/* Trial Info */}
                <p className="text-xs text-[var(--color-text-secondary)] text-center mt-4">
                  No credit card required • 15-day free trial
                </p>
              </div>
            </motion.div>
          ))}
        </div>

        {/* FAQ Section */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
          className="max-w-4xl mx-auto"
        >
          <h3 className="text-3xl font-bold text-[var(--color-text-primary)] text-center mb-8">
            Frequently Asked Questions
          </h3>

          <Accordion type="single" collapsible className="space-y-4">
            {faqsData.map((faq, index) => (
              <AccordionItem 
                key={index} 
                value={`item-${index}`}
                className="bg-white border border-[rgba(15,23,42,0.08)] rounded-lg px-6 shadow-[0_10px_25px_rgba(15,23,42,0.08),0_2px_8px_rgba(15,23,42,0.04)]"
              >
                <AccordionTrigger className="text-[var(--color-text-primary)] hover:text-[var(--color-primary)] text-left font-medium">
                  {faq.question}
                </AccordionTrigger>
                <AccordionContent className="text-[var(--clr-text-2)] leading-relaxed">
                  {faq.answer}
                </AccordionContent>
              </AccordionItem>
            ))}
          </Accordion>
        </motion.div>

        {/* Bottom Trust Message */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
          className="text-center mt-16 pt-12 border-t border-[var(--clr-surface-3)]"
        >
          <p className="text-[var(--clr-text-2)] mb-6">
            Trusted by 2,500+ active contractors across North America
          </p>

          <div className="flex justify-center items-center gap-8 opacity-60">
