              size="lg" 
              className="bg-[var(--clr-surface)] text-blue-900 hover:bg-gray-100 px-8 py-4 text-lg font-semibold"
            >
              Start Your Transformation Today
            </Button>
          </motion.div>
        </div>
      </div>
    </section>
  );
}

