}
.chip { 
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-primary);
}
.btn { 
  font-size: clamp(.9rem, .85rem + .2vw, 1rem); /* 14–16 */
}

/* Typography Ramp - Light Theme Specifications */
/* Ensures consistent type scale across headline, subhead, proof, chips, CTAs */
.hero .h1 {
