            {content.features.title}
          </h2>
          <p className="text-xl text-slate-300 max-w-3xl mx-auto">
            {content.features.subtitle}
          </p>
        </motion.div>

        {/* Feature Navigation Tabs with Micro-Copy */}
        <div className="flex flex-wrap justify-center gap-2 mb-8">
          {features.map((feature, index) => (
            <div key={index} className="text-center">
              <Button
                variant={currentFeature === index ? "default" : "outline"}
                size="sm"
                onClick={() => goToFeature(index)}
                className={`transition-all duration-300 ${
                  currentFeature === index
                    ? "bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-lg transform scale-105"
                    : "border-slate-600 text-slate-300 hover:bg-slate-800 hover:border-slate-500"
                }`}
              >
                {feature.title}
              </Button>
              {currentFeature === index && (
                <motion.p
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.3 }}
                  className="text-sm text-slate-400 mt-2 max-w-xs mx-auto"
                >
                  {microCopy[feature.icon as keyof typeof microCopy]}
                </motion.p>
              )}
            </div>
          ))}
        </div>

        {/* Main Feature Display */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          {/* Feature Content */}
          <AnimatePresence mode="wait">
            <motion.div
              key={currentFeature}
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 50 }}
              transition={{ duration: 0.5 }}
              className="space-y-6"
            >
              <div className="flex items-center space-x-4">
                <div className="w-16 h-16 bg-gradient-to-r from-blue-600 to-purple-600 rounded-xl flex items-center justify-center">
                  <IconComponent className="w-8 h-8 text-white" />
                </div>
                <div>
                  <Badge className="bg-blue-600/20 text-blue-300 border-blue-600/30 mb-2">
                    Feature {currentFeature + 1} of {features.length}
                  </Badge>
                  <h3 className="text-3xl font-bold text-white">
                    {features[currentFeature].title}
                    {features[currentFeature].title.includes('AI') && (
                      <span className="ml-2 px-2 py-1 bg-gradient-to-r from-blue-500 to-purple-500 text-xs font-medium rounded-full">
                        Powered by AI
                      </span>
                    )}
                  </h3>
                </div>
              </div>

              <p className="text-xl text-slate-300 leading-relaxed">
                {features[currentFeature].description}
              </p>

              {/* Feature Details */}
              <div className="space-y-3">
                {features[currentFeature].details?.map((detail, index) => (
                  <motion.div
                    key={index}
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.3, delay: index * 0.1 }}
                    className="flex items-center space-x-3"
                  >
                    <Check className="w-5 h-5 text-green-400 flex-shrink-0" />
                    <span className="text-slate-300">{detail}</span>
                  </motion.div>
                ))}
              </div>

              {/* Navigation Controls */}
              <div className="flex items-center space-x-4 pt-6">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={prevFeature}
                  className="border-slate-600 text-slate-300 hover:bg-slate-800"
                >
                  <ChevronLeft className="w-4 h-4 mr-1" />
                  Previous
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={nextFeature}
                  className="border-slate-600 text-slate-300 hover:bg-slate-800"
                >
                  Next
                  <ChevronRight className="w-4 h-4 ml-1" />
                </Button>
                <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                  <Button
                    onClick={() => setIsVideoModalOpen(true)}
                    className="bg-gradient-to-r from-blue-600 to-purple-600 text-white hover:from-blue-700 hover:to-purple-700 transition-all duration-300 shadow-lg hover:shadow-blue-500/25"
                    size="sm"
                  >
                    <Play className="w-4 h-4 mr-2" />
                    Play Demo (60s)
                  </Button>
                </motion.div>
                <div className="text-slate-500 text-sm">
                  {currentFeature + 1} / {features.length}
                </div>
              </div>
            </motion.div>
          </AnimatePresence>

          {/* Real App Screenshot */}
          <AnimatePresence mode="wait">
            <motion.div
              key={currentFeature}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              transition={{ duration: 0.5 }}
              className="relative"
            >
              {/* iPhone Mockup with Real Screenshot and Hover Glow */}
              <motion.div 
                className="relative bg-black rounded-[28px] p-3 shadow-2xl mx-auto max-w-sm group"
                whileHover={{ 
                  scale: 1.02,
                  boxShadow: "0 0 40px rgba(59, 130, 246, 0.4), 0 25px 50px rgba(0, 0, 0, 0.5)" 
                }}
                transition={{ duration: 0.3 }}
              >
                <div className="relative bg-[var(--clr-surface)] rounded-[24px] overflow-hidden group-hover:ring-2 group-hover:ring-blue-500/20 transition-all duration-300">
                  {/* Status Bar */}
                  <div className="absolute top-0 left-0 right-0 h-8 bg-black/5 flex items-center justify-between px-6 text-sm font-medium text-black/70 z-10">
                    <span>9:41</span>
                    <div className="flex space-x-1">
                      <div className="w-4 h-2 bg-black/70 rounded-sm"></div>
                      <div className="w-1 h-2 bg-black/70 rounded-sm"></div>
                      <div className="w-6 h-2 bg-green-500 rounded-sm"></div>
                    </div>
                  </div>

                  {/* Real App Screenshot */}
                  <img
                    src={screenshotMap[features[currentFeature].icon as keyof typeof screenshotMap]}
                    alt={`${features[currentFeature].title} app screenshot`}
                    className="h-[600px] w-[300px] object-cover"
                  />

                  {/* Home Indicator */}
                  <div className="absolute bottom-2 left-1/2 transform -translate-x-1/2 w-32 h-1 bg-black/30 rounded-full"></div>
                </div>

                {/* Live Feature Badge */}
                <motion.div
                  animate={{ y: [0, -10, 0] }}
                  transition={{ duration: 3, repeat: Infinity }}
                  className="absolute -top-4 -right-4 bg-gradient-to-r from-blue-600 to-purple-600 text-white px-3 py-1 rounded-full text-sm font-medium shadow-lg"
                >
                  Live App
                </motion.div>

                {/* Enhanced Play Demo Button - Show on AI Quotes feature */}
                {currentFeature === 0 && (
                  <motion.button
                    initial={{ opacity: 0, scale: 0.8 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ duration: 0.5, delay: 0.3 }}
                    onClick={() => setIsVideoModalOpen(true)}
                    className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm rounded-[24px] opacity-0 hover:opacity-100 transition-opacity duration-300 group cursor-pointer"
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    {/* Play Button with Pulse Animation */}
                    <motion.div 
                      className="bg-gradient-to-r from-blue-600 to-purple-600 backdrop-blur-md rounded-full p-6 border-2 border-white/30 group-hover:from-blue-500 group-hover:to-purple-500 transition-all duration-300 shadow-2xl"
                      animate={{ 
                        boxShadow: [
                          "0 0 20px rgba(59, 130, 246, 0.5)",
                          "0 0 30px rgba(168, 85, 247, 0.6)",
                          "0 0 20px rgba(59, 130, 246, 0.5)"
                        ]
                      }}
                      transition={{ duration: 2, repeat: Infinity }}
                    >
                      <Play className="w-10 h-10 text-white fill-white" />
                    </motion.div>

                    {/* Demo Text with Glass Effect */}
                    <div className="absolute bottom-6 left-4 right-4 text-center">
                      <motion.div 
                        className="bg-black/60 backdrop-blur-md rounded-xl px-4 py-3 border border-white/20"
                        whileHover={{ backgroundColor: "rgba(0, 0, 0, 0.7)" }}
                      >
                        <div className="text-white font-bold text-base flex items-center justify-center gap-2">
                          <Play className="w-4 h-4 fill-white" />
                          <span>Play Demo</span>
                        </div>
                        <div className="text-blue-200 text-sm mt-1">60-second app walkthrough</div>
                        <div className="text-white/60 text-xs mt-1">See how AI quotes work</div>
                      </motion.div>
                    </div>
                  </motion.button>
                )}
              </motion.div>

              {/* Feature Highlights */}
              <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 gap-4">
                {features[currentFeature].details?.slice(0, 4).map((detail, index) => (
                  <motion.div
                    key={index}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.3, delay: index * 0.1 }}
                    className="bg-slate-800/30 border border-slate-700 rounded-lg p-3 text-center"
                  >
                    <span className="text-sm font-medium text-slate-300">{detail}</span>
                  </motion.div>
                ))}
              </div>
            </motion.div>
          </AnimatePresence>
        </div>
      </div>

      {/* Video Walkthrough Modal */}
      <VideoWalkthroughModal
        isOpen={isVideoModalOpen}
        onClose={() => setIsVideoModalOpen(false)}
      />
    </section>
  );
}

client/src/styles/design-system.css.content:
/* CONSTRUKTR Design System - CEO Specifications */

/* Hero Background - Clean CSS Starfield */
.hero {
  background:
    radial-gradient(1200px 600px at 70% 20%, rgba(91,132,255,.25), transparent 60%),
    radial-gradient(900px 500px at 25% 70%, rgba(42,91,215,.18), transparent 60%),
    linear-gradient(180deg, var(--clr-brand-700) 0%, var(--clr-brand-600) 35%, var(--clr-brand-800) 100%);
  color: var(--clr-text);
  position: relative;
}

.hero .stars {
  position: absolute; 
  inset: 0; 
  pointer-events: none;
  background-image: radial-gradient(rgba(255,255,255,.15) 1px, transparent 1px);
  background-size: 2px 2px; 
  opacity: .14; 
  mix-blend-mode: screen;
}

/* Standardized Chip Styles - CEO Specifications */
.chip-brand {
  background: var(--color-brand-900);
  color: var(--color-brand-300);
  border: 1px solid var(--color-border);
  font-weight: 600;
  font-size: var(--font-size-sm);
  height: 32px;
  padding: 0 var(--space-md);
  border-radius: 9999px;
  transition: all 0.2s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  white-space: nowrap;
}

.chip-brand-sm {
  height: 28px;
  font-size: var(--font-size-xs);
  padding: 0 var(--space-sm);
  font-weight: 600;
}

.chip-brand:hover {
  background: var(--color-brand-800);
  border-color: var(--color-brand-500);
  color: var(--color-brand-200);
}

/* Standardized Button Classes - Exact CEO Specifications */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 12px 24px;
  font-size: 16px;
  font-weight: 600;
  line-height: 1.5;
  border-radius: var(--radius-xl);
  border: none;
  cursor: pointer;
  transition: all 0.2s ease;
  text-decoration: none;
  font-family: 'Inter', system-ui, sans-serif;
  min-height: var(--button-height);
  white-space: nowrap;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn-primary {
  background: var(--color-primary);
  color: var(--color-text-inverse);
  font-weight: 700;
}

.btn-primary:hover {
  background: var(--color-primary-dark);
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-dark {
  background: var(--color-elevated);
  color: var(--color-text-primary);
  border: 1px solid var(--color-border);
}

.btn-dark:hover {
  background: var(--color-border);
  border-color: var(--color-brand-500);
}

.btn-ghost {
  background: transparent;
  color: var(--color-text-secondary);
  border: 1px solid transparent;
}

.btn-ghost:hover {
  background: var(--color-elevated);
  color: var(--color-text-primary);
  border-color: var(--color-border);
}

/* Button size variants */
.btn-sm {
  padding: 8px 16px;
  font-size: 14px;
  min-height: var(--button-height-sm);
}

.btn-lg {
  padding: 16px 32px;
  font-size: 18px;
  min-height: var(--button-height-lg);
}

/* Hover Effect Class */
.speed-hover {
  transition: all 0.15s ease;
}

.speed-hover:hover {
  transform: translateY(-1px);
}

/* Standardized Card Styles */
.card-default {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-lg);
  transition: all 0.2s ease;
}

.card-default:hover {
  border-color: var(--color-brand-500);
  background: var(--color-elevated);
}

/* Phone Mockup - Real App Styling */
.phone-frame {
  background: var(--color-brand-800);
  border-radius: 38px;
  box-shadow: var(--glow-blue);
  padding: 8px;
  min-height: 420px;
}

.phone-screen {
  background: var(--color-brand-900);
  border-radius: 30px;
  overflow: hidden;
  height: 100%;
}

/* Real App Badge */
.real-app-badge {
  background: var(--color-primary);
  color: var(--color-text-inverse);
  font-size: 10px;
  font-weight: 700;
  padding: 4px 8px;
  border-radius: 12px;
  position: absolute;
  top: 8px;
  right: 8px;
  z-index: 10;
}

/* Trust Icons */
.trust-icon {
  color: var(--color-text-secondary);
  opacity: 0.6;
}

.trust-icon:hover {
  opacity: 1;
  color: var(--color-text-primary);
}

/* Education Flow Styling */
.education-step {
  background: var(--color-surface);
  border: var(--card-border);
  border-radius: var(--radius-md);
  padding: 20px;
  transition: all 0.2s ease;
}

.education-step:hover {
  background: var(--color-elevated);
  border-color: var(--color-brand-500);
}

/* ===== MICRO ANIMATIONS - Task 9 ===== */

/* Testimonial Card Animations */
.testimonial-card {
  transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1), 
              box-shadow 0.3s cubic-bezier(0.4, 0, 0.2, 1),
              opacity 0.3s ease;
}

.testimonial-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px -8px rgba(0, 0, 0, 0.12);
}

.testimonial-card .avatar {
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.testimonial-card:hover .avatar {
  transform: scale(1.05);
  box-shadow: 0 0 0 3px var(--color-primary), 0 0 12px rgba(2, 67, 213, 0.25);
}

/* Pricing Card Animations */
.pricing-card {
  transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1),
              box-shadow 0.3s cubic-bezier(0.4, 0, 0.2, 1),
              border-color 0.3s ease;
}

.pricing-card:hover {
  transform: scale(1.02) translateY(-4px);
  box-shadow: 0 20px 40px -12px rgba(0, 0, 0, 0.15);
}

.pricing-card.featured {
  transform: scale(1.02);
  box-shadow: 0 16px 32px -8px rgba(2, 67, 213, 0.2);
}

.pricing-card.featured:hover {
  transform: scale(1.04) translateY(-6px);
  box-shadow: 0 24px 48px -12px rgba(2, 67, 213, 0.25);
}

/* Trade Filter Pills - Active Glow */
.trade-pill {
  transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
}

.trade-pill:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 12px -2px rgba(0, 0, 0, 0.1);
}

.trade-pill.active,
.trade-pill[data-active="true"] {
  background: var(--color-primary);
  color: white;
  box-shadow: 0 0 0 2px rgba(2, 67, 213, 0.3), 0 4px 16px -4px rgba(2, 67, 213, 0.4);
}

.trade-pill.active::after,
.trade-pill[data-active="true"]::after {
  content: '';
  position: absolute;
  inset: -2px;
  border-radius: inherit;
  background: linear-gradient(135deg, rgba(2, 67, 213, 0.4), transparent);
  opacity: 0;
  animation: pill-glow 2s ease-in-out infinite;
  z-index: -1;
}

@keyframes pill-glow {
  0%, 100% { opacity: 0.3; }
  50% { opacity: 0.6; }
}

/* Feature Card Animations */
.feature-card {
  transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.feature-card:hover {
  transform: translateY(-2px);
  border-color: var(--color-primary);
  box-shadow: 0 8px 24px -8px rgba(2, 67, 213, 0.15);
}

.feature-card .icon {
  transition: transform 0.3s ease, color 0.3s ease;
}

.feature-card:hover .icon {
  transform: scale(1.1);
  color: var(--color-primary);
}

/* Button Micro Animations */
.btn,
button {
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

.btn:active,
button:active {
  transform: scale(0.98);
}

/* Fade-in Animation Utility */
.fade-in {
  animation: fadeIn 0.5s ease forwards;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Stagger Children Animation */
.stagger-children > * {
  opacity: 0;
  animation: fadeIn 0.4s ease forwards;
}

.stagger-children > *:nth-child(1) { animation-delay: 0.05s; }
.stagger-children > *:nth-child(2) { animation-delay: 0.1s; }
.stagger-children > *:nth-child(3) { animation-delay: 0.15s; }
.stagger-children > *:nth-child(4) { animation-delay: 0.2s; }
.stagger-children > *:nth-child(5) { animation-delay: 0.25s; }
.stagger-children > *:nth-child(6) { animation-delay: 0.3s; }
.stagger-children > *:nth-child(7) { animation-delay: 0.35s; }
.stagger-children > *:nth-child(8) { animation-delay: 0.4s; }

/* Pulse Animation for CTAs */
.pulse-cta {
  animation: ctaPulse 3s ease-in-out infinite;
}

@keyframes ctaPulse {
  0%, 100% { box-shadow: 0 4px 12px -2px rgba(2, 67, 213, 0.3); }
  50% { box-shadow: 0 6px 20px -2px rgba(2, 67, 213, 0.5); }
}

/* Smooth Scroll Reveal */
.reveal-on-scroll {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}

.reveal-on-scroll.visible {
  opacity: 1;
  transform: translateY(0);
}

/* Scrollbar Hide Utility */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

client/src/components/ui/toaster.tsx.content:
import { useToast } from "@/hooks/use-toast"
import {
  Toast,
  ToastClose,
  ToastDescription,
  ToastProvider,
  ToastTitle,
  ToastViewport,
} from "@/components/ui/toast"

export function Toaster() {
  const { toasts } = useToast()

  return (
    <ToastProvider>
      {toasts.map(function ({ id, title, description, action, ...props }) {
        return (
          <Toast key={id} {...props}>
            <div className="grid gap-1">
              {title && <ToastTitle>{title}</ToastTitle>}
              {description && (
                <ToastDescription>{description}</ToastDescription>
              )}
            </div>
            {action}
            <ToastClose />
          </Toast>
        )
      })}
      <ToastViewport />
    </ToastProvider>
  )
}

client/src/components/DeviceFrame.tsx.content:
import { motion } from "framer-motion";
import OptimizedImage from "./optimized-image";

interface DeviceFrameProps {
  src?: string;
  alt: string;
  className?: string;
  withGlow?: boolean;
  size?: 'mobile' | 'tablet' | 'desktop';
  customContent?: React.ReactNode;
  showBadge?: boolean;
}

export default function DeviceFrame({ 
  src = "", 
  alt, 
  className = "", 
  withGlow = false,
  size = 'desktop',
  customContent,
  showBadge = true
}: DeviceFrameProps) {

  // Standardized device frame sizes with ≥420px width requirement
  const sizeClasses = {
    mobile: {
      container: "h-[560px]",
      width: "w-[420px]", // Minimum 420px width as per policy
      padding: "p-3",
      radius: "rounded-[32px]", // Consistent corner radius
      innerRadius: "rounded-[28px]"
    },
    tablet: {
      container: "h-[640px]",
      width: "w-[480px]", // Above minimum width
      padding: "p-4",
      radius: "rounded-[32px]", // Consistent corner radius
      innerRadius: "rounded-[28px]"
    },
    desktop: {
      container: "h-[720px]",
      width: "w-[540px]", // Large desktop width
      padding: "p-4", 
      radius: "rounded-[32px]", // Consistent corner radius
      innerRadius: "rounded-[28px]"
    }
  };

  const currentSize = sizeClasses[size] || sizeClasses['desktop'];

  return (
    <div className={`relative ${className} mx-auto md:mx-0 px-6 md:px-0`}>
      {/* Consistent Drop Shadow Layers */}
      <div className="absolute top-8 left-4 right-4 bottom-2 bg-black/15 rounded-[28px] blur-2xl transform scale-95"></div>
      <div className="absolute top-6 left-2 right-2 bottom-0 bg-black/25 rounded-[28px] blur-xl transform scale-97"></div>
      <div className="absolute top-4 left-1 right-1 bottom-2 bg-black/10 rounded-[28px] blur-3xl transform scale-90"></div>

      <motion.div 
        className={`relative bg-slate-800 ${currentSize.radius} ${currentSize.padding} ${currentSize.container} ${currentSize.width} shadow-device`}
        style={{
          filter: withGlow 
            ? "drop-shadow(0 30px 80px rgba(0, 0, 0, 0.35)) drop-shadow(0 0 50px rgba(36, 99, 255, 0.3))"
            : "drop-shadow(0 30px 80px rgba(0, 0, 0, 0.35))",
          boxShadow: "0 0 0 1px rgba(255, 255, 255, 0.05)"
        }}
        whileHover={withGlow ? { 
          filter: "drop-shadow(0 35px 90px rgba(0, 0, 0, 0.4)) drop-shadow(0 0 60px rgba(36, 99, 255, 0.4))",
          scale: 1.02,
          y: -5
        } : {
          scale: 1.02,
          y: -2
        }}
        transition={{ duration: 0.3, ease: "easeOut" }}
      >
        <div className={`w-full h-full bg-black ${currentSize.innerRadius} overflow-hidden relative`}>

          {/* Real App Badge - Consistent Top-Right Placement */}
          {showBadge && (
            <div className="absolute top-3 right-3 z-20 bg-[var(--color-primary)] text-white text-xs font-bold px-3 py-1.5 rounded-full shadow-lg">
              Real App
            </div>
          )}

          {/* Status Bar */}
          <div className="absolute top-0 left-0 right-0 h-8 bg-brand-blue/90 flex items-center justify-between px-6 text-sm font-medium text-white z-10">
            <span>9:41</span>
            <div className="flex space-x-1">
              <div className="w-4 h-2 bg-[var(--clr-surface)] rounded-sm"></div>
