/* CONSTRUKTR Brand Button System */
/* Brand Spec: Primary blue #0243D5, 8px radius, 6% lighter on hover, 40% opacity when disabled */

/* Primary Button - Brand Blue */
.btn-primary,
button[data-variant="primary"],
.button-primary {
  background-color: var(--color-primary);
  color: var(--color-text-on-brand);
  border-radius: var(--button-radius); /* 8px */
  height: var(--button-height); /* 48px */
  padding: 0 24px;
  font-size: clamp(0.9rem, 0.85rem + 0.2vw, 1rem); /* 14-16px */
  font-weight: 600;
  border: none;
  cursor: pointer;
  transition: all 0.2s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  text-decoration: none;
  white-space: nowrap;
  box-shadow: var(--shadow-sm);
}

.btn-primary:hover,
button[data-variant="primary"]:hover,
.button-primary:hover {
  background-color: var(--color-primary-hover); /* 6% lighter */
  box-shadow: var(--shadow-md);
  transform: translateY(-1px);
}

.btn-primary:active,
button[data-variant="primary"]:active,
.button-primary:active {
  transform: translateY(0);
  box-shadow: var(--shadow-sm);
}

.btn-primary:disabled,
button[data-variant="primary"]:disabled,
.button-primary:disabled {
  background-color: var(--color-primary-disabled); /* 40% opacity */
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

.btn-primary:focus-visible,
button[data-variant="primary"]:focus-visible,
.button-primary:focus-visible {
  outline: 2px solid var(--color-brand-500);
  outline-offset: 2px;
}

/* Secondary Button - Solid Black (Task 8: Unified Button System) */
.btn-secondary,
button[data-variant="secondary"],
.button-secondary {
  background-color: #000000;  /* Solid black background */
  color: #ffffff;             /* White text */
  border: none;
  border-radius: var(--button-radius);
  height: var(--button-height);
  padding: 0 24px;
  font-size: clamp(0.9rem, 0.85rem + 0.2vw, 1rem);
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  text-decoration: none;
  white-space: nowrap;
  box-shadow: var(--shadow-sm);
}

.btn-secondary:hover,
button[data-variant="secondary"]:hover,
.button-secondary:hover {
  background-color: #1a1a1a;  /* Slightly lighter black on hover */
  box-shadow: var(--shadow-md);
  transform: translateY(-1px);
}

.btn-secondary:active,
button[data-variant="secondary"]:active,
.button-secondary:active {
  transform: translateY(0);
  box-shadow: var(--shadow-sm);
}

.btn-secondary:disabled,
button[data-variant="secondary"]:disabled,
.button-secondary:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* Ghost Button - Minimal */
.btn-ghost,
button[data-variant="ghost"],
.button-ghost {
  background-color: transparent;
  color: var(--color-text-primary);
  border: none;
  border-radius: var(--button-radius);
  height: var(--button-height);
  padding: 0 24px;
  font-size: clamp(0.9rem, 0.85rem + 0.2vw, 1rem);
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  text-decoration: none;
  white-space: nowrap;
}

.btn-ghost:hover,
button[data-variant="ghost"]:hover,
.button-ghost:hover {
  background-color: var(--color-surface);
  color: var(--color-primary);
}

/* Size Variants */
.btn-sm,
button[data-size="sm"],
.button-sm {
  height: var(--button-height-sm); /* 40px */
  padding: 0 16px;
  font-size: 0.875rem;
}

.btn-lg,
button[data-size="lg"],
.button-lg {
  height: var(--button-height-lg); /* 52px */
  padding: 0 32px;
  font-size: 1rem;
}

/* Link Button - Text Only */
.btn-link,
a.button-link {
  background: none;
  border: none;
  color: var(--color-primary);
  text-decoration: underline;
  cursor: pointer;
  font-weight: 500;
  padding: 8px 0;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  transition: color 0.2s ease;
}

.btn-link:hover,
a.button-link:hover {
  color: var(--color-primary-hover);
  text-decoration: underline;
}

/* Icon Buttons */
.btn-icon,
button[data-variant="icon"] {
  width: var(--button-height);
  height: var(--button-height);
  padding: 0;
  border-radius: var(--button-radius);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background-color: transparent;
  border: none;
  color: var(--color-text-primary);
  cursor: pointer;
  transition: all 0.2s ease;
}

.btn-icon:hover,
button[data-variant="icon"]:hover {
  background-color: var(--color-surface);
  color: var(--color-primary);
}

/* Full Width */
.btn-full,
.button-full {
  width: 100%;
}

/* Loading State */
.btn-loading {
  position: relative;
  pointer-events: none;
}

.btn-loading::after {
  content: '';
  position: absolute;
  width: 16px;
  height: 16px;
  border: 2px solid currentColor;
  border-right-color: transparent;
  border-radius: 50%;
  animation: spin 0.6s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Button Groups */
.btn-group {
  display: inline-flex;
  gap: 8px;
}

.btn-group-tight {
  display: inline-flex;
}

.btn-group-tight > button,
.btn-group-tight > .btn-primary,
.btn-group-tight > .btn-secondary {
  border-radius: 0;
  border-right-width: 0;
}

.btn-group-tight > button:first-child,
.btn-group-tight > .btn-primary:first-child,
.btn-group-tight > .btn-secondary:first-child {
  border-top-left-radius: var(--button-radius);
  border-bottom-left-radius: var(--button-radius);
}

.btn-group-tight > button:last-child,
.btn-group-tight > .btn-primary:last-child,
.btn-group-tight > .btn-secondary:last-child {
  border-top-right-radius: var(--button-radius);
  border-bottom-right-radius: var(--button-radius);
  border-right-width: 1px;
}

