                }
              `}
              data-testid={`tab-${cat.id}`}
            >
              {cat.name}
            </button>
          ))}
        </div>

        {/* Active Category */}
        <motion.div
          key={activeCategory}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="mb-8"
