                  bg-white border-gray-100
                  shadow-[0_4px_20px_rgba(15,23,42,0.06)]
                  hover:shadow-[0_8px_30px_rgba(15,23,42,0.12)]
                  hover:border-[var(--color-primary)]/30
                  transition-all duration-300
                `}>
                  {/* Icon */}
